#!/usr/bin/env node

/**
 * Shopify Redirects Manager
 * Manages URL redirects for Shopify stores
 */

import dotenv from 'dotenv';
import https from 'https';

dotenv.config();

const SHOPIFY_ADMIN_TOKEN = process.env.SHOPIFY_ADMIN_TOKEN;
const STORE1_DOMAIN = process.env.SHOPIFY_STORE1_DOMAIN || 'suitenew.myshopify.com';
const STORE2_DOMAIN = process.env.SHOPIFY_STORE2_DOMAIN || '';

// API endpoints
const getRedirectsUrl = (domain) => `https://${domain}/admin/api/2026-04/redirects.json`;
const createRedirectUrl = (domain) => `https://${domain}/admin/api/2026-04/redirects.json`;
const deleteRedirectUrl = (domain, id) => `https://${domain}/admin/api/2026-04/redirects/${id}.json`;
const domainsUrl = (domain) => `https://${domain}/admin/api/2026-04/domains.json`;
const webhooksUrl = (domain) => `https://${domain}/admin/api/2026-04/webhooks.json`;

/**
 * Make authenticated Shopify API request
 */
async function shopifyRequest(url, options = {}) {
  return new Promise((resolve, reject) => {
    const req = https.request(url, {
      method: 'GET',
      headers: {
        'X-Shopify-Access-Token': SHOPIFY_ADMIN_TOKEN,
        'Content-Type': 'application/json',
        ...options.headers
      },
      ...options
    }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);
          if (res.statusCode >= 200 && res.statusCode < 300) {
            resolve(parsed);
          } else {
            reject(new Error(`${res.statusCode}: ${parsed.errors || data}`));
          }
        } catch (e) {
          reject(new Error(`${res.statusCode}: ${data}`));
        }
      });
    });

    req.on('error', reject);
    if (options.body) {
      req.write(options.body);
    }
    req.end();
  });
}

/**
 * List all redirects for a store
 */
async function listRedirects(store = 'store1') {
  const domain = store === 'store2' ? STORE2_DOMAIN : STORE1_DOMAIN;
  
  if (!domain) {
    throw new Error(`${store} domain not configured`);
  }

  try {
    const response = await shopifyRequest(getRedirectsUrl(domain));
    return response.redirects || [];
  } catch (error) {
    console.error(`❌ Fehler beim Abrufen der Redirects für ${store}:`, error.message);
    return [];
  }
}

/**
 * Create a single redirect
 */
