/**
 * Create multiple redirects
 */
async function bulkCreateRedirects(redirects, store = 'store1') {
  const results = [];
  
  for (const { path, target } of redirects) {
    try {
      const result = await createRedirect(path, target, store);
      results.push({ success: true, path, target, result });
    } catch (error) {
      results.push({ success: false, path, target, error: error.message });
    }
  }
  
  return results;
}

